interface CardProps {
  children: ReactNode;
  className?: string;
  noPadding?: boolean;
}

export const Card: React.FC<CardProps> = ({ children, className = '', noPadding = false }) => {
  return (
    <div className={`rounded-[18px] border border-gold/45 shadow-[0_12px_30px_rgba(0,0,0,0.08)] bg-card-gradient overflow-hidden ${noPadding ? '' : 'p-4'} ${className}`}>
      {children}
    </div>
  );
};

interface SectionProps {
  id?: string;
  children: ReactNode;
  className?: string;
}

export const Section: React.FC<SectionProps> = ({ id, children, className = '' }) => {
  return (
    <section id={id} className={`max-w-[520px] mx-auto px-3.5 pt-4 ${className}`}>
      {children}
    </section>
  );
};

interface SectionHeaderProps {
  eyebrow?: string;
  title?: string;
  subtitle?: string;
  align?: 'right' | 'center';
}

export const SectionHeader: React.FC<SectionHeaderProps> = ({ eyebrow, title, subtitle, align = 'right' }) => {
  return (
    <div className={`mb-3 ${align === 'center' ? 'text-center' : 'text-right'}`}>
      {eyebrow && <div className="text-[11px] font-bold text-gold mb-1">{eyebrow}</div>}
      {title && <h2 className="text-[18px] font-extrabold text-brand mb-1.5">{title}</h2>}
      {subtitle && <p className="text-[12px] text-muted leading-relaxed">{subtitle}</p>}
    </div>
  );
};

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'ghost' | 'outline';
  children: ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ variant = 'primary', children, className = '', ...props }) => {
  const baseStyle = "inline-flex items-center justify-center rounded-full px-4 py-2 text-[12px] font-bold cursor-pointer transition-transform active:scale-95 whitespace-nowrap";
  const variants = {
    primary: "bg-gold-gradient text-brand shadow-md border border-transparent",
    ghost: "bg-white border border-gold/80 text-brand shadow-sm",
    outline: "bg-transparent border border-gold text-gold"
  };

  return (
    <button className={`${baseStyle} ${variants[variant]} ${className}`} {...props}>
      {children}
    </button>
  );
};

export const PulseDot = () => (
  <span className="w-[9px] h-[9px] rounded-full bg-gold animate-rf-pulse block" />
);

export const StripContainer: React.FC<{ children: ReactNode, className?: string }> = ({ children, className = '' }) => (
