const Performance: React.FC = () => {
  const [visible, setVisible] = useState(false);
  const sectionRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { threshold: 0.2 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <div ref={sectionRef}>
      <Section id="rf-performance">
        <SectionHeader title="مؤشرات أداء ريفانس المالية" align="right" />
        <div className="bg-white rounded-[20px] border border-gold/60 shadow-lg p-4">
          {perfItems.map((item, idx) => (
            <div key={idx} className="bg-[#F9F8FC] rounded-[14px] p-3 mb-2.5 last:mb-0">
              <div className="flex items-start justify-between mb-2 gap-3">
                <div className="text-[22px] font-extrabold text-brand min-w-[60px] text-left tabular-nums">
                  {visible ? <CountUp end={item.value} suffix="%" /> : '0%'}
                </div>
                <div className="flex-1 text-[12px] text-brand">{item.label}</div>
              </div>
              <div className="w-full h-2 rounded-full bg-[#E5DFC8] overflow-hidden">
                <div 
                  className="h-full rounded-full bg-gradient-to-l from-[#C7A969] to-[#B7A0D8] transition-all duration-[2000ms] ease-out"
                  style={{ width: visible ? `${item.value}%` : '0%' }}
                />
              </div>
            </div>
          ))}
        </div>
      </Section>

      <Section id="rf-numbers" className="mt-4">
        <SectionHeader eyebrow="ريفانس المالية في أرقام" />
        <StripContainer>
          {statsItems.map((stat, idx) => (
            <div key={idx} className="min-w-[130px] bg-white rounded-[18px] border border-gold/70 p-3 text-center shadow-sm snap-center">
              <div className="text-[18px] font-extrabold text-brand mb-1 tabular-nums">
                {visible ? <CountUp end={stat.value} suffix={stat.suffix} /> : '0'}
              </div>
              <div className="text-[11px] text-muted leading-tight">{stat.label}</div>
            </div>
          ))}
        </StripContainer>
      </Section>
    </div>
  );
};

const CountUp: React.FC<{ end: number; suffix?: string; duration?: number }> = ({ end, suffix = '', duration = 2000 }) => {
  const [count, setCount] = useState(0);

  useEffect(() => {
    let startTime: number | null = null;
    const animate = (timestamp: number) => {
      if (!startTime) startTime = timestamp;
      const progress = timestamp - startTime;
      const percentage = Math.min(progress / duration, 1);

      setCount(Math.floor(percentage * end));

      if (progress < duration) {
        requestAnimationFrame(animate);
      }
    };
    requestAnimationFrame(animate);
  }, [end, duration]);

  return <>{count}{suffix}</>;
};

export default Performance;

