import React, { useState } from 'react';
import { Section, SectionHeader, Card, Button } from './Shared';
import { Calculator as CalculatorIcon, RefreshCw } from 'lucide-react';

const Calculator: React.FC = () => {
  const [salary, setSalary] = useState<string>('');
  const [obligations, setObligations] = useState<string>('');
  const [result, setResult] = useState<{
    dbr: number;
    maxInstallment: number;
    available: number;
    status: string;
    statusColor: string;
  } | null>(null);

  const calculate = () => {
    const sal = parseFloat(salary);
    const obs = parseFloat(obligations) || 0;

    if (!sal || sal <= 0) return;

    // Standard DBR limit calculation (assuming 45% for general purpose)
    const DBR_LIMIT = 0.45;
    const maxInstallment = sal * DBR_LIMIT;
    const dbr = (obs / sal) * 100;
    const available = Math.max(0, maxInstallment - obs);

    let status = '';
    let statusColor = '';

    if (dbr <= 30) {
      status = 'ملاءة مالية ممتازة'; // Excellent solvency
      statusColor = 'text-emerald-600';
    } else if (dbr <= 45) {
      status = 'ملاءة مالية جيدة'; // Good solvency
      statusColor = 'text-blue-600';
    } else if (dbr <= 65) {
      status = 'التزامات مرتفعة'; // High obligations
      statusColor = 'text-amber-600';
    } else {
      status = 'تعثر محتمل / عبء عالي'; // Potential default / High burden
      statusColor = 'text-red-600';
    }

    setResult({
      dbr,
      maxInstallment,
      available,
      status,
      statusColor
    });
  };

  const reset = () => {
    setSalary('');
    setObligations('');
    setResult(null);
  };

  return (
    <Section id="calculator">
      <Card>
        <SectionHeader
          eyebrow="أدوات ذكية"
          title="حاسبة الالتزامات والملاءة المالية"
          subtitle="احسب نسبة استقطاعك الحالية وتعرف على قدرتك التمويلية المتبقية تقديراً."
        />

        <div className="space-y-4 mt-2">
          {/* Inputs */}
          <div>
            <label className="block text-[12px] font-bold text-brand mb-1.5">إجمالي الراتب الشهري (ر.س)</label>
            <input
              type="number"
              value={salary}
              onChange={(e) => setSalary(e.target.value)}
              placeholder="مثلاً: 10000"
              className="w-full rounded-[14px] border border-gold/40 bg-white px-3 py-2.5 text-[14px] text-brand focus:outline-none focus:border-gold focus:ring-1 focus:ring-gold/50 transition-all placeholder:text-muted/50"
            />
          </div>

          <div>
            <label className="block text-[12px] font-bold text-brand mb-1.5">إجمالي الأقساط الشهرية الحالية (ر.س)</label>
            <input
              type="number"
              value={obligations}
              onChange={(e) => setObligations(e.target.value)}
              placeholder="مثلاً: 2500"
              className="w-full rounded-[14px] border border-gold/40 bg-white px-3 py-2.5 text-[14px] text-brand focus:outline-none focus:border-gold focus:ring-1 focus:ring-gold/50 transition-all placeholder:text-muted/50"
            />
          </div>

          {/* Action Buttons */}
          <div className="flex gap-2 pt-2">
            <Button onClick={calculate} className="flex-1">
              <CalculatorIcon size={16} className="ml-2" />
              احسب الملاءة
            </Button>
            <Button variant="ghost" onClick={reset}>
              <RefreshCw size={16} />
            </Button>
          </div>

          {/* Results */}
          {result && (
            <div className="mt-4 p-4 rounded-[16px] bg-[#F9F8FC] border border-gold/30 animate-in fade-in slide-in-from-top-2 duration-300">
              <div className="flex items-center justify-between mb-3 border-b border-gold/10 pb-2">
                <span className="text-[12px] text-muted">حالة الملاءة:</span>
                <span className={`text-[13px] font-extrabold ${result.statusColor}`}>{result.status}</span>
              </div>

              <div className="grid grid-cols-2 gap-3 mb-2">
                <div className="bg-white p-2.5 rounded-[12px] border border-gold/20 text-center shadow-sm">
                  <div className="text-[11px] text-muted mb-1">نسبة الاستقطاع (DBR)</div>
                  <div className="text-[16px] font-extrabold text-brand tabular-nums">{result.dbr.toFixed(1)}%</div>
                </div>
                <div className="bg-white p-2.5 rounded-[12px] border border-gold/20 text-center shadow-sm">
                  <div className="text-[11px] text-muted mb-1">القدرة المتبقية (تقديراً)</div>
                  <div className="text-[16px] font-extrabold text-gold tabular-nums">{Math.floor(result.available).toLocaleString()} ر.س</div>
                </div>
              </div>

              <p className="text-[10px] text-muted leading-relaxed mt-2 text-center opacity-80">
                * هذه الأرقام تقديرية بناءً على نسبة استقطاع نظامية 45%، وقد تختلف حسب سياسة جهة التمويل وسجلك الائتماني.
              </p>
            </div>
          )}
        </div>
      </Card>
    </Section>
  );
};

export default Calculator;

