import React, { useState } from 'react';
import { GoogleGenAI } from "@google/genai";
import { Section, SectionHeader, Card, Button } from './Shared';
import { Sparkles, Send, Bot, AlertCircle } from 'lucide-react';

const SUGGESTED_QUESTIONS = [
  "كيف يمكنني إعادة جدولة القرض الشخصي؟",
  "ما هي شروط الإعفاء من المديونية؟",
  "كيف أحسن سجلي الائتماني في سمة؟",
  "ما الفرق بين إعادة الهيكلة والجدولة؟"
];

const AiAssistant: React.FC = () => {
  const [query, setQuery] = useState('');
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleAsk = async (textToAsk: string = query) => {
    if (!textToAsk.trim()) return;

    setLoading(true);
    setError('');
    setResponse('');
    setQuery(textToAsk); // Update input if clicked from suggestions

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const systemInstruction = `
        أنت "مساعد ريفانس الذكي"، مستشار مالي متخصص لمنصة "ريفانس المالية" في المملكة العربية السعودية.

        دورك:
        1. تقديم إجابات مختصرة ومفيدة حول الخدمات المالية، القروض، السجل الائتماني (سمة)، واللوائح المالية السعودية.
        2. التحدث بنبرة مهنية، ودودة، ومطمئنة باللغة العربية.
        3. الإشارة دائمًا إلى أن ريفانس يمكنها المساعدة في تنفيذ هذه الحلول بشكل نظامي.
        4. عدم تقديم فتاوى شرعية أو استشارات قانونية ملزمة، بل توجيهات عامة.

        خدمات ريفانس تشمل: الخدمات التمويلية، القضائية، المصرفية، العقارية، الزكوية، والائتمانية.

        إذا سُئلت عن شيء خارج السياق المالي، اعتذر بلباقة ووجه الحديث للخدمات المالية.
      `;

      const result = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: textToAsk,
        config: {
          systemInstruction: systemInstruction,
          temperature: 0.7,
        }
      });

      setResponse(result.text || 'عذراً، لم أتمكن من استخراج الإجابة حالياً.');
    } catch (err) {
      console.error(err);
      setError('حدث خطأ أثناء الاتصال بالمساعد الذكي. يرجى المحاولة لاحقاً.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Section id="ai-assistant">
      <Card className="border-gold shadow-[0_0_15px_rgba(199,169,105,0.15)] overflow-hidden relative">
        {/* Decorative background accent */}
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-brand via-gold to-brand"></div>

        <SectionHeader 
          eyebrow="جديد: الذكاء الاصطناعي" 
          title="مستشار ريفانس الذكي" 
          subtitle="احصل على إجابات فورية لاستفساراتك المالية مدعومة بتقنيات Gemini."
        />

        <div className="flex flex-col gap-4 mt-2">
          {/* Output Area */}
          {(response || loading || error) && (
            <div className={`rounded-2xl p-4 min-h-[100px] transition-all duration-300 ${error ? 'bg-red-50 border border-red-100' : 'bg-white border border-gold/20'}`}>
              {loading ? (
                <div className="flex flex-col items-center justify-center h-full py-2 gap-3">
                  <Sparkles className="text-gold animate-spin" size={24} />
                  <span className="text-[12px] text-muted animate-pulse">جاري تحليل استفسارك مالياً...</span>
                </div>
              ) : error ? (
                <div className="flex items-center gap-2 text-red-600 text-[12px]">
                  <AlertCircle size={16} />
                  {error}
                </div>
              ) : (
                <div className="flex items-start gap-3">
                  <div className="w-8 h-8 rounded-full bg-brand text-gold flex items-center justify-center shrink-0 mt-1 shadow-sm">
                    <Bot size={18} />
                  </div>
                  <div className="flex-1">
                    <p className="text-[13px] text-brand leading-7 whitespace-pre-line">
                      {response}
                    </p>
                    <div className="mt-3 pt-2 border-t border-gray-100 text-[10px] text-muted flex items-center gap-1">
                      <Sparkles size={10} className="text-gold" />
                      إجابة مولدة بواسطة الذكاء الاصطناعي (Gemini). للاستشارات الرسمية تواصل معنا مباشرة.
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Input Area */}
          <div className="relative">
            <textarea
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="اكتب استفسارك المالي هنا... (مثال: كيف يتم احتساب النسبة المتناقصة؟)"
              className="w-full bg-white border border-gold/40 rounded-[16px] p-3 pl-12 text-[13px] text-brand placeholder:text-muted/60 focus:outline-none focus:border-gold focus:ring-1 focus:ring-gold/30 min-h-[50px] resize-none shadow-inner"
              rows={2}
            />
            <button 
              onClick={() => handleAsk()}
              disabled={loading || !query.trim()}
              className="absolute left-2 bottom-2 w-8 h-8 rounded-full bg-brand text-gold flex items-center justify-center hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {loading ? <span className="w-3 h-3 border-2 border-gold border-t-transparent rounded-full animate-spin" /> : <Send size={14} className="ml-0.5" />}
            </button>
          </div>

          {/* Suggested Chips */}
          <div className="flex flex-wrap gap-2 justify-end">
            {SUGGESTED_QUESTIONS.map((q, idx) => (
              <button
                key={idx}
                onClick={() => handleAsk(q)}
                className="text-[10px] px-3 py-1.5 rounded-full bg-white border border-gold/30 text-muted hover:border-gold hover:text-brand hover:bg-gold/5 transition-colors cursor-pointer"
              >
                {q}
              </button>
            ))}
          </div>
        </div>
      </Card>
    </Section>
  );
};

export default AiAssistant;

