        <div className="flex-1 overflow-y-auto py-2">
            {menuItems.map((item, idx) => (
                <a 
                  key={idx} 
                  href={item.href} 
                  target={item.href.startsWith('http') ? "_blank" : "_self"}
                  onClick={onClose}
                  className="block px-6 py-4 text-[14px] font-bold text-brand border-b border-gray-50 hover:bg-[#FFFBF2] hover:text-gold transition-colors text-right"
                  rel={item.href.startsWith('http') ? "noopener noreferrer" : undefined}
                >
                    {item.label}
                </a>
            ))}
        </div>

        {/* Footer */}
        <div className="p-6 bg-[#F9F8FC] border-t border-gold/20 flex flex-col items-center">
            <div className="text-[15px] font-extrabold text-brand mb-4">ريفانس المالية</div>
