            ]
          }
        });

        setTranscription(response.text || "عذراً، لم أتمكن من استخراج النص من التسجيل.");
        setIsAnalyzing(false);
      };
    } catch (error) {
      console.error("Transcription error", error);
      setTranscription("حدث خطأ أثناء معالجة الصوت. يرجى المحاولة مرة أخرى.");
      setIsAnalyzing(false);
    }
  };

