             </div>

             {/* Region & City */}
             <div>
                <label className="block text-[12px] font-bold text-brand mb-1.5">المنطقة <span className="text-red-500">*</span></label>
                <select 
                   name="region" 
                   value={region} 
                   onChange={(e) => setRegion(e.target.value)}
