              <div className="space-y-2 mb-5">
                {product.features.map((feat, i) => (
                  <div key={i} className="flex items-center gap-2 text-[12px] text-brand">
                    <div className="w-4 h-4 rounded-full bg-green-50 text-green-600 flex items-center justify-center shrink-0">
                      <Check size={10} />
                    </div>
                    <span>{feat}</span>
                  </div>
                ))}
              </div>

              <Button 
                onClick={() => setSelectedProduct(product)}
                className={`w-full h-11 text-[13px] gap-2 shadow-md
                  ${product.recommended ? 'bg-gold-gradient text-brand' : 'bg-white border border-gold text-brand hover:bg-gold/5'}
                `}
              >
                <span>شراء الباقة الآن</span>
                <Zap size={16} className={product.recommended ? 'fill-brand/20' : 'fill-gold/20'} />
              </Button>
            </div>
          ))}
        </div>
      </Section>

      {/* Checkout Modal */}
      {selectedProduct && (
        <CheckoutModal 
          product={selectedProduct} 
          onClose={() => setSelectedProduct(null)} 
        />
      )}
    </>
  );
};

