                <input type="number" name="nationalId" required className="w-full p-2.5 rounded-[12px] border border-gold/30 text-[13px] focus:border-gold focus:ring-1 focus:ring-gold/30 outline-none" placeholder="10 أرقام" />
             </div>

             {/* Mobile & Job */}
             <div>
                <label className="block text-[12px] font-bold text-brand mb-1.5">رقم الجوال <span className="text-red-500">*</span></label>
                <input type="tel" name="mobile" required className="w-full p-2.5 rounded-[12px] border border-gold/30 text-[13px] focus:border-gold focus:ring-1 focus:ring-gold/30 outline-none" placeholder="05xxxxxxxx" />
             </div>
             <div>
                <label className="block text-[12px] font-bold text-brand mb-1.5">الحالة الوظيفية <span className="text-red-500">*</span></label>
                <select name="jobStatus" required className="w-full p-2.5 rounded-[12px] border border-gold/30 text-[13px] focus:border-gold focus:ring-1 focus:ring-gold/30 outline-none bg-white">
