import React, { useState, useEffect } from 'react';
import { Menu, Moon, Sun } from 'lucide-react';
import SideMenu from './SideMenu';

const Header: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isDark, setIsDark] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };

    // Check system preference or localStorage
    if (localStorage.theme === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      document.documentElement.classList.add('dark');
      setIsDark(true);
    } else {
      document.documentElement.classList.remove('dark');
      setIsDark(false);
    }

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleTheme = () => {
    if (isDark) {
      document.documentElement.classList.remove('dark');
      localStorage.theme = 'light';
      setIsDark(false);
    } else {
      document.documentElement.classList.add('dark');
      localStorage.theme = 'dark';
      setIsDark(true);
    }
  };

  return (
    <>
      <header 
        className={`fixed top-0 left-0 right-0 z-50 flex items-center justify-center h-[70px] px-4 transition-all duration-500 
        ${isScrolled 
          ? 'backdrop-blur-md bg-white/40 dark:bg-black/40 border-b border-white/20 dark:border-white/10 shadow-sm supports-[backdrop-filter]:bg-white/20' 
          : 'bg-transparent border-transparent shadow-none'}`}
      >
        <div className="w-full max-w-[520px] flex justify-center relative">

          {/* Dark Mode Toggle - Absolute Left */}
          <button 
            onClick={toggleTheme}
            className={`absolute left-0 top-1/2 -translate-y-1/2 w-8 h-8 flex items-center justify-center rounded-full transition-all duration-300 ${
               isScrolled 
                 ? 'text-brand dark:text-white hover:bg-black/5 dark:hover:bg-white/10' 
                 : 'text-white hover:bg-white/20'
            }`}
            aria-label="Toggle Dark Mode"
          >
            {isDark ? <Sun size={18} strokeWidth={2} /> : <Moon size={18} strokeWidth={2} />}
          </button>

          {/* Menu Button - Absolute Right */}
          <button 
            onClick={() => setIsMenuOpen(true)}
            className={`absolute right-0 top-1/2 -translate-y-1/2 p-2 rounded-full transition-colors ${
               isScrolled ? 'text-brand dark:text-gold hover:bg-black/5 dark:hover:bg-white/10' : 'text-white hover:bg-white/10'
            }`}
            aria-label="Open Menu"
          >
            <Menu size={28} />
          </button>

          <a href="/" className="transition-opacity hover:opacity-90">
            <img 
              src="https://j.top4top.io/p_36106srws0.png" 
              alt="Rifans Financial" 
              className="h-[35px] object-contain drop-shadow-sm transition-all duration-300"
            />
          </a>
        </div>
      </header>

      <SideMenu isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} />
    </>
  );
};

