import React, { useState, useEffect } from 'react';
import { Menu, Moon, Sun } from 'lucide-react';
import SideMenu from './SideMenu';

const Header: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isDark, setIsDark] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };

    // Check system preference or localStorage
    if (localStorage.theme === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      document.documentElement.classList.add('dark');
      setIsDark(true);
    } else {
      document.documentElement.classList.remove('dark');
      setIsDark(false);
    }

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleTheme = () => {
    if (isDark) {
      document.documentElement.classList.remove('dark');
      localStorage.theme = 'light';
      setIsDark(false);
    } else {
      document.documentElement.classList.add('dark');
      localStorage.theme = 'dark';
      setIsDark(true);
    }
  };

  return (
    <>
      <header 
        className={`fixed top-0 left-0 right-0 z-50 flex items-center justify-center h-[70px] px-4 transition-all duration-500 
        ${isScrolled 
          ? 'backdrop-blur-md bg-white/40 dark:bg-black/40 border-b border-white/20 dark:border-white/10 shadow-sm supports-[backdrop-filter]:bg-white/20' 
          : 'bg-transparent border-transparent shadow-none'}`}
      >
        <div className="w-full max-w-[520px] h-full flex items-center justify-center relative">

          {/* Dark Mode Toggle - Left Aligned */}
          <button 
            onClick={toggleTheme}
            dir="ltr"
            className={`absolute left-0 top-1/2 -translate-y-1/2 w-[42px] h-[22px] rounded-full border flex items-center relative transition-all duration-300 z-20 group cursor-pointer hover:scale-105 active:scale-95 ${
               isDark 
                 ? 'bg-black/90 border-white/40 shadow-[0_0_10px_rgba(255,255,255,0.15)]' 
                 : 'bg-white/90 border-brand/20 shadow-sm'
            }`}
            aria-label="Toggle Dark Mode"
          >
             {/* Text Labels */}
             <div className="absolute inset-0 flex items-center justify-between px-1.5 pointer-events-none select-none">
                <span className={`text-[8px] font-black font-sans tracking-widest transition-opacity duration-300 ${isDark ? 'opacity-100 text-white' : 'opacity-0'}`}>ON</span>
                <span className={`text-[8px] font-black font-sans tracking-widest transition-opacity duration-300 ${!isDark ? 'opacity-100 text-brand' : 'opacity-0'}`}>OFF</span>
