                   <Moon size={9} className="text-white fill-white/20" />
                ) : (
                   <Sun size={10} className="text-gold fill-gold/20" />
                )}
             </div>
          </button>

          {/* Logo Centered */}
          <a href="/" className="transition-opacity hover:opacity-90 flex items-center z-10">
            <img 
              src="https://j.top4top.io/p_36106srws0.png" 
              alt="Rifans Financial" 
              className="h-[32px] object-contain drop-shadow-sm transition-all duration-300"
            />
          </a>

          {/* Menu Button - Absolute Right */}
          <button 
