<?xml version="1.0" encoding="UTF-8"?>
<files>
    <file path="SideMenu.tsx">
        <contents>
import React, { useState, useEffect, useCallback } from 'react';
import { SocialIcon } from 'react-social-icons';
import { menuItems } from './menuItems';
import './SideMenu.css';

interface SideMenuProps {
    isOpen: boolean;
    onClose: () => void;
    onItemClick?: () => void;
}

const SideMenu: React.FC&lt;SideMenuProps&gt; = ({ isOpen, onClose, onItemClick }) =&gt; {
    const [isClosing, setIsClosing] = useState(false);

    const handleLinkClick = (e: React.MouseEvent&lt;HTMLAnchorElement&gt;, href: string) =&gt; {
        e.preventDefault();
        onItemClick?.();
        if (href.startsWith('#')) {
            const target = document.querySelector(href);
            if (target) {
                // Ensure overflow is removed before scrolling
                setIsClosing(true);
                setTimeout(() =&gt; {
                    target.scrollIntoView({ behavior: 'smooth' });
                    setIsClosing(false); // Reset isClosing after scroll
                }, 200); // Adjust timeout as needed
            }
        } else {
            // External link or non-anchor link, just close the menu and let browser handle it
            onClose();
            window.location.href = href;
        }
    };

    // Close menu when clicking outside of it
    useEffect(() =&gt; {
        const handleClickOutside = (event: MouseEvent) =&gt; {
            if (isOpen) {
                const sideMenu = document.querySelector('.side-menu');
                if (sideMenu &amp;&amp; !sideMenu.contains(event.target as Node)) {
                    onClose();
                }
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        return () =&gt; {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [isOpen, onClose]);

    useEffect(() =&gt; {
        if (!isOpen) {
            setIsClosing(false);
        }
    }, [isOpen]);

    return (
        &lt;div className={`side-menu ${isOpen ? 'open' : ''} ${isClosing ? 'closing' : ''}`}&gt;
            &lt;div className="menu-content"&gt;
                &lt;button className="close-button" onClick={onClose}&gt;&amp;times;&lt;/button&gt;
                &lt;ul className="menu-items"&gt;
                    {menuItems.map((item, index) =&gt; (
                        &lt;li key={index} className="menu-item"&gt;
                            &lt;a
                                href={item.link}
                                onClick={(e) =&gt; handleLinkClick(e, item.link)}
                                className="menu-link"
                            &gt;
                                {item.label}
                            &lt;/a&gt;
                        &lt;/li&gt;
                    ))}
                &lt;/ul&gt;
