                      </div>
                  </div>
               </div>

               {/* Financial Info */}
               <div className="bg-white dark:bg-[#12031a] rounded-[18px] border border-gold/20 p-5 shadow-sm">
                  <h3 className="text-[13px] font-bold text-gold flex items-center gap-2 mb-4">
                      <Building2 size={16} />
