هذه تحطها فوق الأكواد في <script> داخل صفحتك.

function generateFileNumber() {
  const year = new Date().getFullYear();
  const random = Math.floor(1000 + Math.random() * 9000);
  return `RF-${year}-${random}`;
}

الخطوة 2 — كود إنشاء ملف جديد (تسجيل جديد)

هذا ينحط في صفحة التسجيل عندما العميل يضغط "إنشاء ملف".

async function createNewFile() {
  const customer_name = document.getElementById("customer_name").value;
  const national_id = document.getElementById("national_id").value;
  const phone_number = document.getElementById("phone_number").value;
  const service_type = document.getElementById("service_type").value;

  const file_number = generateFileNumber();

  const { data, error } = await supabase
    .from('requests')
    .insert([{
      request_type: 'new_file',
      customer_name,
      national_id,
      phone_number,
      service_type,
      file_number
    }])
    .select();

  if (error) {
    alert("⚠️ حدث خطأ أثناء إنشاء الملف");
    console.log(error);
    return;
  }

  // نحفظ بيانات العميل في المتصفح
  localStorage.setItem("currentFile", JSON.stringify(data[0]));

  alert("🎉 تم إنشاء ملفك بنجاح");
  window.location.href = "dashboard.html"; // صفحة لوحة العميل
}


الخطوة 3 — كود تسجيل الدخول (عنده ملف سابق)

إذا العميل عنده ملف موجود مسبقًا.

async function loginToFile() {
  const national_id = document.getElementById("login_national_id").value;
  const phone_number = document.getElementById("login_phone_number").value;

  const { data, error } = await supabase
    .from("requests")
    .select("*")
    .eq("national_id", national_id)
    .eq("phone_number", phone_number)
    .order("created_at", { ascending: false })
    .limit(1)
    .single();

  if (error || !data) {
    alert("⚠️ لا يوجد ملف مطابق للبيانات المدخلة");
    return;
  }

  // حفظ بيانات الملف في المتصفح
  localStorage.setItem("currentFile", JSON.stringify(data));

  alert("✔️ تم تسجيل دخولك");
  window.location.href = "dashboard.html";
}

الخطوة 4 — كود قراءة بيانات العميل داخل لوحة التحكم dashboard.html

window.onload = function() {
  const file = JSON.parse(localStorage.getItem("currentFile"));

  if (!file) {
    window.location.href = "login.html";
    return;
  }

  document.getElementById("file_number").innerText = file.file_number;
  document.getElementById("customer_name").innerText = file.customer_name;
  document.getElementById("service_type").innerText = file.service_type;
  document.getElementById("national_id").innerText = file.national_id;
  document.getElementById("phone_number").innerText = file.phone_number;
};

الخطوة 5 — كود تسجيل خروج

function logout() {
  localStorage.removeItem("currentFile");
  window.location.href = "login.html";
}

