import React, { useState, useEffect } from 'react';
import { Menu, User, Sun, Moon, Languages } from 'lucide-react';
import SideMenu from './SideMenu';
import AuthModal from './AuthModal';
import CustomerDashboard from './CustomerDashboard';
import { UserProfile } from '../types';
import { useLanguage } from '../contexts/LanguageContext';

const Header: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [showDashboard, setShowDashboard] = useState(false);
  const [user, setUser] = useState<UserProfile | null>(null);
  const { t, toggleLanguage, language } = useLanguage();

  // Theme state
  const [isDark, setIsDark] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };

    window.addEventListener('scroll', handleScroll);

    // Initialize theme based on localStorage or system preference
    const savedTheme = localStorage.getItem('theme');
    const systemPrefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;

    if (savedTheme === 'dark' || (!savedTheme && systemPrefersDark)) {
      setIsDark(true);
      document.documentElement.classList.add('dark');
    } else {
      setIsDark(false);
      document.documentElement.classList.remove('dark');
    }

    // Check for active session (Step 4: Read customer data on load)
    const currentFileStr = localStorage.getItem('currentFile');
    if (currentFileStr) {
      try {
        const currentUser = JSON.parse(currentFileStr);
        setUser(currentUser);
      } catch (e) {
        console.error("Error parsing session", e);
        localStorage.removeItem('currentFile');
      }
    }

    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLogin = (loggedInUser: UserProfile) => {
    setUser(loggedInUser);
    setShowAuthModal(false);
    setShowDashboard(true); // Open dashboard immediately after login
  };

  const handleLogout = () => {
    setUser(null);
    setShowDashboard(false);
    // Step 5: Logout - remove currentFile
    localStorage.removeItem('currentFile');
  };

  const handleLogoClick = (e: React.MouseEvent) => {
    e.preventDefault();
    window.scrollTo({ top: 0, behavior: 'smooth' });
    window.history.pushState(null, '', '/');
  };

  const toggleTheme = () => {
    if (isDark) {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
      setIsDark(false);
    } else {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
      setIsDark(true);
    }
  };

  return (
    <>
      <header 
        className={`fixed top-0 left-0 right-0 z-50 flex items-center justify-center h-[70px] px-4 transition-all duration-500 
        ${isScrolled 
          ? 'backdrop-blur-md bg-white/40 dark:bg-black/40 border-b border-white/20 dark:border-white/10 shadow-sm supports-[backdrop-filter]:bg-white/20' 
          : 'bg-transparent border-transparent shadow-none'}`}
      >
        <div className="w-full max-w-[520px] h-full flex items-center justify-between relative">

          {/* Left Side: Login Button */}
          <div className="z-20 flex items-center">
             {user ? (
               <button 
                 onClick={() => setShowDashboard(true)}
                 className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[11px] font-bold transition-all ${isScrolled ? 'bg-brand/10 text-brand dark:text-white dark:bg-white/10' : 'bg-white/20 text-white backdrop-blur-md border border-white/30'}`}
               >
                 <div className="w-5 h-5 rounded-full bg-gold flex items-center justify-center text-brand">
                    <User size={12} />
                 </div>
                 <span>{t('my_profile')}</span>
               </button>
             ) : (
               <button 
                 onClick={() => setShowAuthModal(true)}
                 className={`flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold transition-all ${isScrolled ? 'bg-brand text-gold shadow-md' : 'bg-white text-brand shadow-lg'}`}
               >
                 <User size={13} />
                 <span>{t('login_register')}</span>
               </button>
             )}
          </div>

          {/* Center: Logo */}
          <a href="/" onClick={handleLogoClick} className="absolute left-1/2 -translate-x-1/2 transition-opacity hover:opacity-90 flex items-center z-10">
            <img 
              src="https://j.top4top.io/p_36106srws0.png" 
              alt="Rifans Financial" 
              className="h-[32px] object-contain drop-shadow-sm transition-all duration-300"
            />
          </a>

          {/* Right Side: Language, Theme Toggle & Menu Button */}
          <div className="flex items-center gap-1.5 z-20">
            {/* Language Toggle */}
            <button 
              onClick={toggleLanguage}
              className={`flex items-center justify-center w-8 h-8 rounded-full transition-colors font-bold text-[10px] ${
                 isScrolled ? 'text-brand dark:text-gold hover:bg-black/5 dark:hover:bg-white/10' : 'text-white hover:bg-white/10'
              }`}
              aria-label="Toggle Language"
            >
              {language === 'ar' ? 'EN' : 'ع'}
            </button>

            <button 
              onClick={toggleTheme}
              className={`p-2 rounded-full transition-colors ${
                 isScrolled ? 'text-brand dark:text-gold hover:bg-black/5 dark:hover:bg-white/10' : 'text-white hover:bg-white/10'
              }`}
              aria-label={t('theme_toggle')}
            >
              {isDark ? <Sun size={20} /> : <Moon size={20} />}
            </button>

            <button 
              onClick={() => setIsMenuOpen(true)}
              className={`p-2 rounded-full transition-colors ${
                 isScrolled ? 'text-brand dark:text-gold hover:bg-black/5 dark:hover:bg-white/10' : 'text-white hover:bg-white/10'
              }`}
              aria-label={t('menu_open')}
            >
              <Menu size={26} />
            </button>
          </div>

        </div>
      </header>

      <SideMenu isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} />

      {showAuthModal && (
        <AuthModal 
          onClose={() => setShowAuthModal(false)} 
          onLogin={handleLogin} 
        />
      )}

      {showDashboard && user && (
        <CustomerDashboard 
          user={user} 
          onClose={() => setShowDashboard(false)} 
          onLogout={handleLogout} 
        />
      )}
    </>
  );
};

export default Header;

import React, { useState } from 'react';
import { X, User, Phone, CreditCard, ArrowRight, LogIn, UserPlus, AlertCircle, Briefcase } from 'lucide-react';
import { Button } from './Shared';
import { UserProfile } from '../types';

interface AuthModalProps {
  onClose: () => void;
  onLogin: (user: UserProfile) => void;
}

const AuthModal: React.FC<AuthModalProps> = ({ onClose, onLogin }) => {
  const [isRegister, setIsRegister] = useState(true);
  const [formData, setFormData] = useState({
    fullName: '',
    nationalId: '',
    mobile: '',
    serviceType: '',
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
    setError('');
  };

  const validateInput = () => {
    if (formData.nationalId.length !== 10) return "رقم الهوية يجب أن يتكون من 10 أرقام";
    if (!formData.mobile.startsWith('05') || formData.mobile.length !== 10) return "رقم الجوال يجب أن يبدأ بـ 05 ويتكون من 10 أرقام";
    if (isRegister) {
      if (formData.fullName.length < 3) return "الاسم يجب أن يكون ثلاثياً على الأقل";
      if (!formData.serviceType) return "يرجى اختيار نوع الخدمة المطلوبة";
    }
    return null;
  };

  // Step 1: Generate File Number
  const generateFileNumber = () => {
    const year = new Date().getFullYear();
    const random = Math.floor(1000 + Math.random() * 9000); // 4 digit random
    return `RF-${year}-${random}`;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const validationError = validateInput();
    if (validationError) {
      setError(validationError);
      return;
    }

    setLoading(true);

    // Simulation of API Call / LocalStorage Logic
    setTimeout(() => {
      const storageKey = `user_${formData.nationalId}`;
      const existingUserStr = localStorage.getItem(storageKey);

      if (isRegister) {
        if (existingUserStr) {
          setError("هذا المستخدم مسجل مسبقاً، الرجاء تسجيل الدخول.");
          setLoading(false);
          return;
        }
        // Step 2: Create New File
        const fileNumber = generateFileNumber();
        const newUser: UserProfile = {
          ...formData,
          fileNumber: fileNumber, 
          joinDate: new Date().toISOString(),
        };
        // Save to Database (Mock)
        localStorage.setItem(storageKey, JSON.stringify(newUser));
        // Set Session (Mock for "Login to File")
        localStorage.setItem('currentFile', JSON.stringify(newUser));

        onLogin(newUser);
      } else {
        // Step 3: Login to File
        if (existingUserStr) {
          const user = JSON.parse(existingUserStr);
          // Simple validation check (Mobile match)
          if (user.mobile === formData.mobile) {
             // Backward compatibility: If old user doesn't have fileNumber, generate one
             if (!user.fileNumber) {
                user.fileNumber = generateFileNumber();
                localStorage.setItem(storageKey, JSON.stringify(user));
             }
             // Set Session
             localStorage.setItem('currentFile', JSON.stringify(user));
             onLogin(user);
          } else {
             setError("رقم الجوال غير مطابق لرقم الهوية المسجل.");
          }
        } else {
          setError("لا يوجد حساب بهذا الرقم، يرجى التسجيل أولاً.");
