            <button
              type="button"
              onClick={() => { setIsRegister(false); setError(''); }}
              className={`flex-1 py-2 text-[12px] font-bold rounded-lg transition-all ${!isRegister ? 'bg-white dark:bg-brand text-brand dark:text-gold shadow-sm' : 'text-muted'}`}
            >
              تسجيل دخول
            </button>
