const WaiveRequestForm: React.FC<WaiveRequestFormProps> = ({ onClose }) => {
  const [requestId, setRequestId] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const [region, setRegion] = useState('');
  const [products, setProducts] = useState([{ id: 1, type: '', amount: '' }]);
  const [documents, setDocuments] = useState([{ id: 1, type: '', file: null }]);
  const [totalAmount, setTotalAmount] = useState(0);

  // Signature logic
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [hasSignature, setHasSignature] = useState(false);

  useEffect(() => {
    // Generate Request ID
    const now = new Date();
    const dd = String(now.getDate()).padStart(2,'0');
    const mm = String(now.getMonth()+1).padStart(2,'0');
    const yy = String(now.getFullYear()).slice(-2);
    const rand = Math.floor(100 + Math.random()*900);
    setRequestId(`RF-${dd}${mm}${yy}-${rand}`);
  }, []);

  useEffect(() => {
    // Calculate total
    const total = products.reduce((sum, p) => sum + (parseFloat(p.amount) || 0), 0);
    setTotalAmount(total);
  }, [products]);

  // Signature Canvas Handling
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.lineWidth = 2;
      ctx.lineCap = 'round';
      ctx.strokeStyle = '#22042C';
    }

    const resizeCanvas = () => {
       const parent = canvas.parentElement;
       if(parent) {
         canvas.width = parent.clientWidth;
         canvas.height = 130;
         if (ctx) {
            ctx.lineWidth = 2;
            ctx.lineCap = 'round';
            ctx.strokeStyle = '#22042C';
         }
       }
    };
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);
    return () => window.removeEventListener('resize', resizeCanvas);
  }, []);

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    setHasSignature(true);
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    const rect = canvas.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    ctx.beginPath();
    ctx.moveTo(clientX - rect.left, clientY - rect.top);
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (!canvas || !ctx) return;

    e.preventDefault(); // Prevent scrolling on touch
    const rect = canvas.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    ctx.lineTo(clientX - rect.left, clientY - rect.top);
    ctx.stroke();
  };

  const stopDrawing = () => {
    setIsDrawing(false);
  };

  const clearSignature = () => {
    const canvas = canvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      setHasSignature(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!hasSignature) {
      alert('يرجى التوقيع في المربع المخصص قبل الإرسال.');
      return;
    }

    setIsSubmitting(true);

    const form = e.target as HTMLFormElement;
    const formData = new FormData(form);

    // Add Signature
    if (canvasRef.current) {
        formData.append('signatureData', canvasRef.current.toDataURL());
    }
    // Add Products Total
    formData.append('productsTotal', totalAmount.toString());

    try {
      const response = await fetch("https://api.web3forms.com/submit", {
        method: "POST",
        body: formData
      });

      if (response.ok) {
        setIsSuccess(true);
      } else {
        alert("حدث خطأ أثناء الإرسال، يرجى المحاولة لاحقاً.");
      }
    } catch (error) {
      console.error(error);
      alert("حدث خطأ في الاتصال.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const addProduct = () => setProducts([...products, { id: Date.now(), type: '', amount: '' }]);
  const removeProduct = (id: number) => setProducts(products.filter(p => p.id !== id));
  const updateProduct = (id: number, field: 'type' | 'amount', value: string) => {
    setProducts(products.map(p => p.id === id ? { ...p, [field]: value } : p));
  };

  const addDocument = () => setDocuments([...documents, { id: Date.now(), type: '', file: null }]);
  const removeDocument = (id: number) => setDocuments(documents.filter(d => d.id !== id));

  if (isSuccess) {
    return (
      <div className="fixed inset-0 z-[100] bg-[#F5F4FA] flex items-center justify-center p-4">
        <div className="bg-white rounded-[24px] border border-gold shadow-2xl p-8 max-w-md w-full text-center animate-in zoom-in duration-300">
           <div className="w-20 h-20 rounded-full bg-green-50 border border-green-200 flex items-center justify-center mx-auto mb-4">
              <CheckCircle className="text-green-600" size={40} />
           </div>
           <h2 className="text-[22px] font-extrabold text-brand mb-2">تم استلام طلبك بنجاح</h2>
           <p className="text-[13px] text-muted mb-6 leading-relaxed">
             شكراً لك. تم تسجيل طلب الإعفاء الخاص بك برقم 
             <span className="font-bold text-brand block mt-1 text-[16px]">{requestId}</span>
             سيقوم فريقنا بالتواصل معك قريباً لاستكمال الإجراءات.
           </p>
           <Button onClick={onClose} className="w-full">العودة للرئيسية</Button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#F5F4FA] overflow-y-auto overflow-x-hidden animate-in slide-in-from-bottom duration-300">
      {/* Top Bar */}
      <div className="sticky top-0 left-0 right-0 bg-white/80 backdrop-blur-md border-b border-gold/30 h-[60px] flex items-center justify-between px-4 z-50 shadow-sm">
        <button onClick={onClose} className="p-2 rounded-full hover:bg-gray-100 text-brand">
          <ArrowRight size={20} />
        </button>
        <span className="text-[14px] font-extrabold text-brand">نموذج طلب الإعفاء</span>
        <div className="w-10"></div> {/* Spacer */}
      </div>

      <div className="max-w-[980px] mx-auto px-4 py-6 pb-12">
        <form onSubmit={handleSubmit} className="bg-white rounded-[16px] border border-gold/45 shadow-[0_18px_45px_rgba(0,0,0,0.06)] p-5 sm:p-8">

          {/* Hidden Web3Forms Inputs */}
          <input type="hidden" name="access_key" value="0932dd66-854a-41aa-8b0e-c372589bd60a" />
          <input type="hidden" name="from_name" value="موقع ريفانس المالية" />
          <input type="hidden" name="subject" value={`طلب إعفاء جديد - ${requestId}`} />
          <input type="hidden" name="requestId" value={requestId} />

          <div className="mb-6 border-b border-gray-100 pb-4">
             <div className="flex justify-between items-center mb-2">
               <h1 className="text-[20px] font-extrabold text-brand">بيانات الطلب الأساسية</h1>
               <span className="bg-[#FFFBF2] text-gold px-3 py-1 rounded-full text-[12px] font-bold border border-gold/30 tracking-wider font-mono">{requestId}</span>
             </div>
             <p className="text-[12px] text-muted">يرجى تعبئة جميع البيانات المطلوبة بدقة لضمان سرعة معالجة الطلب.</p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
             {/* Name */}
             <div className="md:col-span-2">
               <label className="block text-[12px] font-bold text-brand mb-1.5">الاسم الثلاثي <span className="text-red-500">*</span></label>
               <div className="flex gap-2">
                 <input type="text" name="firstName" placeholder="الأول" required className="w-full p-2.5 rounded-[12px] border border-gold/30 text-[13px] focus:border-gold focus:ring-1 focus:ring-gold/30 outline-none" />
